"""Thread-safe Team Collaboration Manager.

Standard library only, ASCII only. Implements user, project, task, messaging,
performance, and reporting subsystems with a single shared RLock for
thread safety and deep-copy isolation on all returned entities.
"""

import copy
import csv
import io
import threading
from datetime import datetime
from enum import Enum


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------

class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    TEAM_PERFORMANCE = "team_performance"
    PROJECT_PROGRESS = "project_progress"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------

class TeamCollaborationError(Exception):
    pass


class ValidationError(TeamCollaborationError):
    pass


class NotFoundError(TeamCollaborationError):
    pass


class AuthorizationError(TeamCollaborationError):
    pass


class DuplicateError(TeamCollaborationError):
    pass


class ConflictError(TeamCollaborationError):
    pass


# ---------------------------------------------------------------------------
# Data classes
# ---------------------------------------------------------------------------

class Attachment:
    def __init__(self, filename, size, uploaded_by, uploaded_at):
        self.filename = filename
        self.size = size
        self.uploaded_by = uploaded_by
        self.uploaded_at = uploaded_at


class User:
    def __init__(self, id, username, email, role, created_at):
        self.id = id
        self.username = username
        self.email = email
        self.role = role
        self.created_at = created_at


class Project:
    def __init__(self, id, name, description, start_date, end_date, owner_id):
        self.id = id
        self.name = name
        self.description = description
        self.start_date = start_date
        self.end_date = end_date
        self.owner_id = owner_id


class Task:
    def __init__(self, id, project_id, title, status, assignee_id,
                 deadline, started_at, completed_at):
        self.id = id
        self.project_id = project_id
        self.title = title
        self.status = status
        self.assignee_id = assignee_id
        self.deadline = deadline
        self.started_at = started_at
        self.completed_at = completed_at


class Message:
    def __init__(self, id, author_id, body, project_id, task_id,
                 parent_id, attachments, created_at, edited_at):
        self.id = id
        self.author_id = author_id
        self.body = body
        self.project_id = project_id
        self.task_id = task_id
        self.parent_id = parent_id
        self.attachments = attachments
        self.created_at = created_at
        self.edited_at = edited_at


class Rating:
    def __init__(self, id, rater_id, ratee_id, score, feedback,
                 task_id, created_at):
        self.id = id
        self.rater_id = rater_id
        self.ratee_id = ratee_id
        self.score = score
        self.feedback = feedback
        self.task_id = task_id
        self.created_at = created_at


# ---------------------------------------------------------------------------
# Sub-stores (thin wrappers that hold the shared lock reference)
# ---------------------------------------------------------------------------

class _SubStore:
    """Base sub-store holding a reference to the shared lock."""

    def __init__(self, lock):
        self._lock = lock


class _UserStore(_SubStore):
    pass


class _ProjectStore(_SubStore):
    pass


class _TaskStore(_SubStore):
    pass


class _MessageStore(_SubStore):
    pass


class _PerformanceStore(_SubStore):
    pass


class _ReportStore(_SubStore):
    pass


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------

class TeamCollaborationManager:
    """Thread-safe collaboration manager with shared RLock across all stores."""

    def __init__(self, now=None):
        self._lock = threading.RLock()
        self._now = now if now is not None else datetime.now
        self._next_id = 1

        # Internal storage
        self._users = {}          # id -> User
        self._username_idx = {}   # username -> id
        self._email_idx = {}      # email -> id

        self._projects = {}       # id -> Project
        self._tasks = {}          # id -> Task
        self._task_by_project = {}  # project_id -> set of task_ids
        self._task_by_assignee = {}  # user_id -> set of task_ids

        self._messages = {}       # id -> Message
        self._msg_by_project = {}  # project_id -> list of msg_ids
        self._msg_by_task = {}    # task_id -> list of msg_ids

        self._ratings = []        # list of Rating
        self._ratings_by_ratee = {}  # ratee_id -> list of Rating

        # Sub-stores sharing the same lock
        self.users = _UserStore(self._lock)
        self.projects = _ProjectStore(self._lock)
        self.tasks = _TaskStore(self._lock)
        self.messages = _MessageStore(self._lock)
        self.performance = _PerformanceStore(self._lock)
        self.reports = _ReportStore(self._lock)

    def _alloc_id(self):
        eid = self._next_id
        self._next_id += 1
        return eid

    # ------------------------------------------------------------------
    # Users
    # ------------------------------------------------------------------

    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            if not username or not username.strip():
                raise ValidationError("username required")
            if not email:
                raise ValidationError("email required")
            if "@" not in email:
                raise ValidationError("invalid email")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be UserRole")
            if username in self._username_idx:
                raise DuplicateError("username taken")
            if email in self._email_idx:
                raise DuplicateError("email taken")
            uid = self._alloc_id()
            user = User(uid, username, email, role, self._now())
            self._users[uid] = user
            self._username_idx[username] = uid
            self._email_idx[email] = uid
            return copy.deepcopy(user)

    def get_user(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user not found")
            return copy.deepcopy(self._users[user_id])

    def list_users(self):
        with self._lock:
            return [copy.deepcopy(self._users[uid])
                    for uid in sorted(self._users)]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user not found")
            user = self._users[user_id]
            if username is not None:
                if username != user.username:
                    if username in self._username_idx:
                        raise DuplicateError("username taken")
                    del self._username_idx[user.username]
                    self._username_idx[username] = user_id
                    user.username = username
            if email is not None:
                if "@" not in email:
                    raise ValidationError("invalid email")
                if email != user.email:
                    if email in self._email_idx:
                        raise DuplicateError("email taken")
                    del self._email_idx[user.email]
                    self._email_idx[email] = user_id
                    user.email = email
            if role is not None:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be UserRole")
                user.role = role
            return copy.deepcopy(user)

    def delete_user(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user not found")
            # Check if user owns any project
            for p in self._projects.values():
                if p.owner_id == user_id:
                    raise ConflictError("user owns a project")
            # Check if user has non-completed assigned tasks
            assigned = self._task_by_assignee.get(user_id, set())
            for tid in assigned:
                if tid in self._tasks:
                    if self._tasks[tid].status != TaskStatus.COMPLETED:
                        raise ConflictError("user has open tasks")
            user = self._users[user_id]
            del self._username_idx[user.username]
            del self._email_idx[user.email]
            del self._users[user_id]
            if user_id in self._task_by_assignee:
                del self._task_by_assignee[user_id]

    # ------------------------------------------------------------------
    # Projects
    # ------------------------------------------------------------------

    def create_project(self, name, start_date, end_date, owner_id,
                       description=""):
        with self._lock:
            if not name or not name.strip():
                raise ValidationError("name required")
            if end_date < start_date:
                raise ValidationError("end_date before start_date")
            if owner_id not in self._users:
                raise NotFoundError("owner not found")
            pid = self._alloc_id()
            project = Project(pid, name, description, start_date,
                              end_date, owner_id)
            self._projects[pid] = project
            self._task_by_project[pid] = set()
            self._msg_by_project[pid] = []
            return copy.deepcopy(project)

    def get_project(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("project not found")
            return copy.deepcopy(self._projects[project_id])

    def list_projects(self):
        with self._lock:
            return [copy.deepcopy(self._projects[pid])
                    for pid in sorted(self._projects)]

    def update_project(self, project_id, name=None, start_date=None,
                       end_date=None, description=None):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("project not found")
            project = self._projects[project_id]
            if name is not None:
                if not name or not name.strip():
                    raise ValidationError("name required")
                project.name = name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            if project.end_date < project.start_date:
                raise ValidationError("end_date before start_date")
            return copy.deepcopy(project)

    def delete_project(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("project not found")
            # Cascade-delete tasks
            task_ids = set(self._task_by_project.get(project_id, set()))
            for tid in task_ids:
                task = self._tasks.get(tid)
                if task and task.assignee_id is not None:
                    assignee_set = self._task_by_assignee.get(
                        task.assignee_id, set())
                    assignee_set.discard(tid)
                # Remove task messages
                if tid in self._msg_by_task:
                    for mid in self._msg_by_task[tid]:
                        self._messages.pop(mid, None)
                    del self._msg_by_task[tid]
                self._tasks.pop(tid, None)
            del self._task_by_project[project_id]
            # Cascade-delete project messages
            if project_id in self._msg_by_project:
                for mid in self._msg_by_project[project_id]:
                    self._messages.pop(mid, None)
                del self._msg_by_project[project_id]
            del self._projects[project_id]

    # ------------------------------------------------------------------
    # Tasks
    # ------------------------------------------------------------------

    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("project not found")
            if not title or not title.strip():
                raise ValidationError("title required")
            if assignee_id is not None and assignee_id not in self._users:
                raise NotFoundError("assignee not found")
            project = self._projects[project_id]
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline before project start")
            tid = self._alloc_id()
            task = Task(tid, project_id, title, TaskStatus.NOT_STARTED,
                        assignee_id, deadline, None, None)
            self._tasks[tid] = task
            self._task_by_project[project_id].add(tid)
            if assignee_id is not None:
                self._task_by_assignee.setdefault(assignee_id, set()).add(tid)
            return copy.deepcopy(task)

    def get_task(self, task_id):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("task not found")
            return copy.deepcopy(self._tasks[task_id])

    def list_tasks_by_project(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("project not found")
            task_ids = sorted(self._task_by_project.get(project_id, set()))
            return [copy.deepcopy(self._tasks[tid]) for tid in task_ids]

    def list_tasks_by_assignee(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user not found")
            task_ids = sorted(self._task_by_assignee.get(user_id, set()))
            return [copy.deepcopy(self._tasks[tid]) for tid in task_ids
                    if tid in self._tasks]

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("task not found")
            if assignee_id not in self._users:
                raise NotFoundError("assignee not found")
            task = self._tasks[task_id]
            # Remove from old assignee index
            if task.assignee_id is not None:
                old_set = self._task_by_assignee.get(task.assignee_id, set())
                old_set.discard(task_id)
            task.assignee_id = assignee_id
            self._task_by_assignee.setdefault(assignee_id, set()).add(task_id)
            return copy.deepcopy(task)

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("task not found")
            if new_assignee_id not in self._users:
                raise NotFoundError("assignee not found")
            task = self._tasks[task_id]
            if task.assignee_id is not None:
                old_set = self._task_by_assignee.get(task.assignee_id, set())
                old_set.discard(task_id)
            task.assignee_id = new_assignee_id
            self._task_by_assignee.setdefault(
                new_assignee_id, set()).add(task_id)
            return copy.deepcopy(task)

    def unassign_task(self, task_id):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("task not found")
            task = self._tasks[task_id]
            if task.assignee_id is not None:
                old_set = self._task_by_assignee.get(task.assignee_id, set())
                old_set.discard(task_id)
            task.assignee_id = None
            return copy.deepcopy(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("task not found")
            task = self._tasks[task_id]
            if deadline is not None:
                project = self._projects[task.project_id]
                if deadline < project.start_date:
                    raise ValidationError("deadline before project start")
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id, status):
        with self._lock:
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be TaskStatus")
            if task_id not in self._tasks:
                raise NotFoundError("task not found")
            task = self._tasks[task_id]
            task.status = status
            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            return copy.deepcopy(task)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------

    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None):
        with self._lock:
            if author_id not in self._users:
                raise NotFoundError("author not found")
            if project_id is None and task_id is None:
                raise ValidationError("must specify project_id or task_id")
            if project_id is not None and task_id is not None:
                raise ValidationError(
                    "specify only one of project_id or task_id")
            if project_id is not None and project_id not in self._projects:
                raise NotFoundError("project not found")
            if task_id is not None and task_id not in self._tasks:
                raise NotFoundError("task not found")
            if parent_id is not None and parent_id not in self._messages:
                raise NotFoundError("parent message not found")
            if (not body or not body.strip()) and not attachments:
                raise ValidationError("body or attachments required")
            now = self._now()
            att_list = []
            if attachments:
                for fname, data in attachments:
                    att_list.append(Attachment(fname, len(data),
                                              author_id, now))
            mid = self._alloc_id()
            msg = Message(mid, author_id, body, project_id, task_id,
                          parent_id, att_list, now, None)
            self._messages[mid] = msg
            if project_id is not None:
                self._msg_by_project.setdefault(project_id, []).append(mid)
            if task_id is not None:
                self._msg_by_task.setdefault(task_id, []).append(mid)
            return copy.deepcopy(msg)

    def edit_message(self, message_id, author_id, new_body):
        with self._lock:
            if message_id not in self._messages:
                raise NotFoundError("message not found")
            msg = self._messages[message_id]
            if msg.author_id != author_id:
                raise AuthorizationError("not the author")
            if not new_body or not new_body.strip():
                raise ValidationError("body required")
            msg.body = new_body
            msg.edited_at = self._now()
            return copy.deepcopy(msg)

    def add_attachment(self, message_id, author_id, filename, data):
        with self._lock:
            if message_id not in self._messages:
                raise NotFoundError("message not found")
            msg = self._messages[message_id]
            if msg.author_id != author_id:
                raise AuthorizationError("not the author")
            if not filename or not filename.strip():
                raise ValidationError("filename required")
            att = Attachment(filename, len(data), author_id, self._now())
            msg.attachments.append(att)
            return copy.deepcopy(msg)

    def list_messages_by_project(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("project not found")
            msg_ids = self._msg_by_project.get(project_id, [])
            return [copy.deepcopy(self._messages[mid])
                    for mid in msg_ids if mid in self._messages]

    def list_messages_by_task(self, task_id):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("task not found")
            msg_ids = self._msg_by_task.get(task_id, [])
            return [copy.deepcopy(self._messages[mid])
                    for mid in msg_ids if mid in self._messages]

    def delete_message(self, message_id, author_id):
        with self._lock:
            if message_id not in self._messages:
                raise NotFoundError("message not found")
            msg = self._messages[message_id]
            if msg.author_id != author_id:
                raise AuthorizationError("not the author")
            if msg.project_id is not None:
                lst = self._msg_by_project.get(msg.project_id, [])
                if message_id in lst:
                    lst.remove(message_id)
            if msg.task_id is not None:
                lst = self._msg_by_task.get(msg.task_id, [])
                if message_id in lst:
                    lst.remove(message_id)
            del self._messages[message_id]

    # ------------------------------------------------------------------
    # Performance
    # ------------------------------------------------------------------

    def get_completion_rate(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user not found")
            task_ids = self._task_by_assignee.get(user_id, set())
            total = len(task_ids)
            if total == 0:
                return 0.0
            completed = sum(
                1 for tid in task_ids
                if tid in self._tasks
                and self._tasks[tid].status == TaskStatus.COMPLETED
            )
            return completed / total

    def get_average_completion_time(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user not found")
            task_ids = self._task_by_assignee.get(user_id, set())
            times = []
            for tid in task_ids:
                if tid not in self._tasks:
                    continue
                t = self._tasks[tid]
                if (t.status == TaskStatus.COMPLETED
                        and t.started_at and t.completed_at):
                    times.append(
                        (t.completed_at - t.started_at).total_seconds())
            if not times:
                return None
            return sum(times) / len(times)

    def submit_rating(self, rater_id, ratee_id, score, feedback="",
                      task_id=None):
        with self._lock:
            if not isinstance(score, int) or score < 1 or score > 5:
                raise ValidationError("score must be 1-5")
            if rater_id == ratee_id:
                raise ConflictError("cannot rate yourself")
            if rater_id not in self._users:
                raise NotFoundError("rater not found")
            if ratee_id not in self._users:
                raise NotFoundError("ratee not found")
            if task_id is not None and task_id not in self._tasks:
                raise NotFoundError("task not found")
            rid = self._alloc_id()
            rating = Rating(rid, rater_id, ratee_id, score, feedback,
                            task_id, self._now())
            self._ratings.append(rating)
            self._ratings_by_ratee.setdefault(ratee_id, []).append(rating)
            return copy.deepcopy(rating)

    def get_ratings_summary(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user not found")
            user_ratings = self._ratings_by_ratee.get(user_id, [])
            count = len(user_ratings)
            avg = (sum(r.score for r in user_ratings) / count
                   if count else 0.0)
            return {
                "count": count,
                "average": avg,
                "ratings": [copy.deepcopy(r) for r in user_ratings],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user not found")
            task_ids = self._task_by_assignee.get(user_id, set())
            tasks = [self._tasks[tid] for tid in task_ids
                     if tid in self._tasks]
            total = len(tasks)
            completed = sum(1 for t in tasks
                           if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks
                             if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks
                             if t.status == TaskStatus.NOT_STARTED)
            completion_rate = completed / total if total else 0.0
            times = []
            for t in tasks:
                if (t.status == TaskStatus.COMPLETED
                        and t.started_at and t.completed_at):
                    times.append(
                        (t.completed_at - t.started_at).total_seconds())
            avg_time = sum(times) / len(times) if times else None
            user_ratings = self._ratings_by_ratee.get(user_id, [])
            rating_count = len(user_ratings)
            rating_avg = (sum(r.score for r in user_ratings) / rating_count
                          if rating_count else 0.0)
            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_avg,
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------

    def project_progress_report(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("project not found")
            task_ids = self._task_by_project.get(project_id, set())
            tasks = [self._tasks[tid] for tid in task_ids
                     if tid in self._tasks]
            total = len(tasks)
            status_counts = {
                TaskStatus.NOT_STARTED.value: 0,
                TaskStatus.IN_PROGRESS.value: 0,
                TaskStatus.COMPLETED.value: 0,
            }
            for t in tasks:
                status_counts[t.status.value] += 1
            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = completed / total if total else 0.0
            now = self._now()
            overdue = sum(
                1 for t in tasks
                if t.deadline is not None
                and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )
            per_assignee = {}
            for t in tasks:
                if t.assignee_id is not None:
                    if t.assignee_id not in per_assignee:
                        per_assignee[t.assignee_id] = {
                            "total": 0, "completed": 0}
                    per_assignee[t.assignee_id]["total"] += 1
                    if t.status == TaskStatus.COMPLETED:
                        per_assignee[t.assignee_id]["completed"] += 1
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None and project_id not in self._projects:
                raise NotFoundError("project not found")
            # Determine tasks in scope
            if project_id is not None:
                task_ids = self._task_by_project.get(project_id, set())
            else:
                task_ids = set(self._tasks.keys())
            # Group by assignee
            assignee_tasks = {}
            for tid in task_ids:
                if tid not in self._tasks:
                    continue
                t = self._tasks[tid]
                if t.assignee_id is not None:
                    assignee_tasks.setdefault(t.assignee_id, []).append(t)
            rows = []
            for uid in sorted(assignee_tasks.keys()):
                user = self._users.get(uid)
                if user is None:
                    continue
                tasks = assignee_tasks[uid]
                total = len(tasks)
                completed = sum(1 for t in tasks
                               if t.status == TaskStatus.COMPLETED)
                comp_rate = completed / total if total else 0.0
                times = []
                for t in tasks:
                    if (t.status == TaskStatus.COMPLETED
                            and t.started_at and t.completed_at):
                        times.append(
                            (t.completed_at - t.started_at).total_seconds())
                avg_time = sum(times) / len(times) if times else None
                user_ratings = self._ratings_by_ratee.get(uid, [])
                rc = len(user_ratings)
                ra = (sum(r.score for r in user_ratings) / rc
                      if rc else 0.0)
                rows.append({
                    "user_id": uid,
                    "username": user.username,
                    "total_tasks": total,
                    "completed_tasks": completed,
                    "completion_rate": comp_rate,
                    "average_completion_time": avg_time,
                    "rating_count": rc,
                    "rating_average": ra,
                })
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user not found")
            task_ids = self._task_by_assignee.get(user_id, set())
            tasks = [self._tasks[tid] for tid in sorted(task_ids)
                     if tid in self._tasks]
            total = len(tasks)
            completed = sum(1 for t in tasks
                           if t.status == TaskStatus.COMPLETED)
            comp_rate = completed / total if total else 0.0
            times = []
            for t in tasks:
                if (t.status == TaskStatus.COMPLETED
                        and t.started_at and t.completed_at):
                    times.append(
                        (t.completed_at - t.started_at).total_seconds())
            avg_time = sum(times) / len(times) if times else None
            task_entries = [copy.deepcopy(t) for t in tasks]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "completion_rate": comp_rate,
                "average_completion_time": avg_time,
                "tasks": task_entries,
            }

    def export_report(self, report, fmt):
        with self._lock:
            if not isinstance(fmt, ReportFormat):
                raise ValidationError("fmt must be ReportFormat")
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")
            if fmt == ReportFormat.CSV:
                return self._export_csv(report)
            else:
                return self._export_pdf(report)

    def _export_csv(self, report):
        output = io.StringIO()
        writer = csv.writer(output)
        report_type = report.get("report_type", "")
        if report_type == ReportType.TEAM_PERFORMANCE.value:
            cols = ["user_id", "username", "total_tasks",
                    "completed_tasks", "completion_rate",
                    "average_completion_time", "rating_count",
                    "rating_average"]
            writer.writerow(cols)
            for row in report.get("rows", []):
                writer.writerow([row.get(c, "") for c in cols])
        elif report_type == ReportType.PROJECT_PROGRESS.value:
            writer.writerow(["metric", "value"])
            writer.writerow(["project_id", report.get("project_id", "")])
            writer.writerow(["total_tasks", report.get("total_tasks", 0)])
            writer.writerow(["completion_rate",
                            report.get("completion_rate", 0.0)])
            writer.writerow(["overdue_tasks",
                            report.get("overdue_tasks", 0)])
        elif report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            writer.writerow(["metric", "value"])
            writer.writerow(["user_id", report.get("user_id", "")])
            writer.writerow(["total_tasks", report.get("total_tasks", 0)])
            writer.writerow(["completed_tasks",
                            report.get("completed_tasks", 0)])
            writer.writerow(["completion_rate",
                            report.get("completion_rate", 0.0)])
        else:
            writer.writerow(["key", "value"])
            for k, v in report.items():
                writer.writerow([k, v])
        return output.getvalue()

    def _export_pdf(self, report):
        # Minimal valid PDF structure
        objects = []
        # Object 1: Catalog
        objects.append(b"1 0 obj\n<< /Type /Catalog /Pages 2 0 R >>\nendobj")
        # Object 2: Pages
        objects.append(
            b"2 0 obj\n<< /Type /Pages /Kids [3 0 R] /Count 1 >>\nendobj")
        # Object 3: Page
        objects.append(
            b"3 0 obj\n<< /Type /Page /Parent 2 0 R "
            b"/MediaBox [0 0 612 792] >>\nendobj")
        # Build body
        header = b"%PDF-1.4\n"
        body = b""
        offsets = []
        for obj in objects:
            offsets.append(len(header) + len(body))
            body += obj + b"\n"
        xref_offset = len(header) + len(body)
        xref = b"xref\n"
        xref += ("0 {0}\n".format(len(objects) + 1)).encode("ascii")
        xref += b"0000000000 65535 f \n"
        for off in offsets:
            xref += ("{0:010d} 00000 n \n".format(off)).encode("ascii")
        trailer = (
            "trailer\n<< /Size {0} /Root 1 0 R >>\n"
            "startxref\n{1}\n%%EOF\n"
        ).format(len(objects) + 1, xref_offset).encode("ascii")
        return header + body + xref + trailer
